examples.good:
class AccountCache {
    // Only cache non-sensitive display data, never CVV or raw PAN
    static let shared = NSCache<NSString, NSString>()
    func cacheMaskedAccount(maskedPan: String) {
        AccountCache.shared.setObject(maskedPan as NSString, forKey: "masked_pan")
    }
}

let statementCache: NSCache<NSString, NSData> = {
    let cache = NSCache<NSString, NSData>()
    cache.countLimit = 50 // Max 50 statements
    cache.totalCostLimit = 10 * 1024 * 1024 // Max 10 MB
    return cache
}()

examples.bad:
class TransactionCache {
    static let shared = NSCache<NSString, NSArray>()
    // No observers registered to clear cache on memory warning or backgrounding
}

examples.good:
class TransactionCache {
    static let shared = NSCache<NSString, NSArray>()
    init() {
        NotificationCenter.default.addObserver(self, selector: #selector(clearCache), name: UIApplication.didReceiveMemoryWarningNotification, object: nil)
        NotificationCenter.default.addObserver(self, selector: #selector(clearCache), name: UIApplication.didEnterBackgroundNotification, object: nil)
    }
    @objc private func clearCache() {
        TransactionCache.shared.removeAllObjects()
    }
}
